[{"path":"package.json","content":"{
  "name": "my-vue-app",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite --port 5173",
    "build": "vue-tsc && vite build",
    "preview": "vite preview",
    "test": "vitest run"
  },
  "dependencies": {
    "vue": "^3.4.31",
    "vue-router": "^4.4.0"
  },
  "devDependencies": {
    "@vitejs/plugin-vue": "^5.0.5",
    "@vue/test-utils": "^2.4.6",
    "typescript": "^5.5.3",
    "vite": "^5.3.4",
    "vitest": "^2.0.4",
    "vue-tsc": "^2.0.26"
  }
}"},{"path":"vite.config.ts","content":"import { defineConfig } from 'vite';
import vue from '@vitejs/plugin-vue';

export default defineConfig({
  plugins: [vue()],
  server: { port: 5173 },
});"},{"path":"tsconfig.json","content":"{
  "compilerOptions": {
    "target": "ES2020",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "strict": true,
    "jsx": "preserve",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "esModuleInterop": true,
    "lib": ["ES2020", "DOM", "DOM.Iterable"],
    "skipLibCheck": true,
    "noEmit": true,
    "paths": { "@/*": ["./src/*"] }
  },
  "include": ["src/**/*.ts", "src/**/*.vue"]
}"},{"path":"index.html","content":"<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>my-vue-app</title>
</head>
<body>
  <div id="app"></div>
  <script type="module" src="/src/main.ts"></script>
</body>
</html>"},{"path":"src/main.ts","content":"import { createApp } from 'vue';
import App from './App.vue';
import router from './router';

createApp(App).use(router).mount('#app');"},{"path":"src/App.vue","content":"<template>
  <div id="app">
    <h1>my-vue-app</h1>
    <router-view />
  </div>
</template>

<script setup lang="ts">
</script>"},{"path":"src/router/index.ts","content":"import { createRouter, createWebHistory } from 'vue-router';

const routes = [
  { path: '/', component: () => import('../views/Home.vue') },
];

export default createRouter({
  history: createWebHistory(),
  routes,
});"},{"path":"src/views/Home.vue","content":"<template>
  <div>
    <h2>Home</h2>
    <p>Welcome to my-vue-app</p>
  </div>
</template>

<script setup lang="ts">
</script>"},{"path":"src/vite-env.d.ts","content":"/// <reference types="vite/client" />
declare module '*.vue' {
  import type { DefineComponent } from 'vue';
  const component: DefineComponent<{}, {}, any>;
  export default component;
}"},{"path":"Dockerfile","content":"# Stage 1: Build
FROM node:20-alpine AS build
WORKDIR /app
COPY package*.json ./
RUN npm ci
COPY . .
RUN npm run build

# Stage 2: Serve
FROM nginx:alpine
COPY --from=build /app/dist /usr/share/nginx/html
COPY nginx.conf /etc/nginx/conf.d/default.conf
EXPOSE 80
CMD ["nginx", "-g", "daemon off;"]"},{"path":"docker-compose.yml","content":"version: "3.8"
services:
  app:
    build: .
    ports:
      - "80:80""},{"path":".dockerignore","content":"node_modules
dist
.git
.env"},{"path":"nginx.conf","content":"server {
    listen 80;
    server_name localhost;
    root /usr/share/nginx/html;
    index index.html;

    location / {
        try_files $uri $uri/ /index.html;
    }

    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }
}"},{"path":"unit_tests/Home.test.ts","content":"import { describe, it, expect } from 'vitest';
import { mount } from '@vue/test-utils';
import Home from '../src/views/Home.vue';

